// OAuth 2.1 Metadata für Claude.ai Discovery
const baseUrl = 'https://oauth.srv768465.hstgr.cloud';

return [{
    json: {
        issuer: baseUrl,
        authorization_endpoint: `${baseUrl}/webhook/oauth/authorize`,
        token_endpoint: `${baseUrl}/webhook/oauth/token`,
        userinfo_endpoint: `${baseUrl}/webhook/oauth/userinfo`,
        jwks_uri: `${baseUrl}/webhook/oauth/jwks`,
        registration_endpoint: `${baseUrl}/webhook/oauth/register`,
        scopes_supported: [
            "mcp:read",
            "mcp:execute", 
            "tools:weather",
            "tools:memory",
            "vector:search"
        ],
        response_types_supported: ["code", "token"],
        grant_types_supported: ["client_credentials", "authorization_code"],
        token_endpoint_auth_methods_supported: ["client_secret_post", "client_secret_basic"],
        code_challenge_methods_supported: ["S256"],
        revocation_endpoint: `${baseUrl}/webhook/oauth/revoke`,
        introspection_endpoint: `${baseUrl}/webhook/oauth/introspect`
    }
}];

// OAuth Authorization für Claude.ai
const crypto = require('crypto');

try {
    const query = $('OAuth Authorization Endpoint').first().json.query || {};
    const { 
        response_type, 
        client_id, 
        redirect_uri, 
        scope, 
        state,
        code_challenge,
        code_challenge_method 
    } = query;

    console.log('OAuth Authorization Request:', { response_type, client_id, scope });

    // Validierung für Claude.ai
    if (response_type !== 'code') {
        return [{
            json: {
                error: 'unsupported_response_type',
                error_description: 'Only authorization_code flow supported'
            }
        }];
    }

    if (!client_id || !redirect_uri) {
        return [{
            json: {
                error: 'invalid_request',
                error_description: 'Missing client_id or redirect_uri'
            }
        }];
    }

    // Authorization Code generieren
    const authCode = crypto.randomUUID();

    // Code temporär speichern (für Demo - in Produktion: Redis/DB)
    global.authCodes = global.authCodes || {};
    global.authCodes[authCode] = {
        client_id,
        scope: scope || 'mcp:read mcp:execute',
        code_challenge,
        code_challenge_method,
        redirect_uri,
        expires_at: Date.now() + 600000, // 10 Minuten
        used: false
    };

    console.log('Authorization code generated:', authCode);

    // Redirect zu Claude.ai mit Authorization Code
    const redirectUrl = new URL(redirect_uri);
    redirectUrl.searchParams.set('code', authCode);
    if (state) {
        redirectUrl.searchParams.set('state', state);
    }

    // HTTP Redirect Response
    $execution.setCurrentExecutionData({
        http: {
            statusCode: 302,
            headers: {
                'Location': redirectUrl.toString(),
                'Cache-Control': 'no-store'
            }
        }
    });

    return [{
        json: {
            redirected: true,
            redirect_uri: redirectUrl.toString(),
            authorization_code: authCode
        }
    }];

} catch (error) {
    console.error('Authorization Error:', error);
    return [{
        json: {
            error: 'server_error',
            error_description: 'Authorization failed: ' + error.message
        }
    }];
}

// Vereinfachter OAuth Token für Claude.ai
const crypto = require('crypto');

try {
    const body = $('Simplified Token Endpoint').first().json.body || {};
    const { grant_type, client_id, client_secret, code, redirect_uri } = body;

    console.log('Token Request:', { grant_type, client_id });

    // Client Credentials Flow (vereinfacht)
    if (grant_type === 'client_credentials') {
        // Vereinfachte Client-Validation
        const validClients = {
            'claude-mcp-client': $env.OAUTH_CLIENT_SECRET,
            'chatgpt-mcp-client': $env.OAUTH_CLIENT_SECRET,
            'ai-service-client': $env.OAUTH_CLIENT_SECRET
        };

        if (!validClients[client_id] || validClients[client_id] !== client_secret) {
            return [{
                json: {
                    error: 'invalid_client',
                    error_description: 'Invalid client credentials'
                }
            }];
        }

        // Einfacher Access Token (ohne JWT - für Claude.ai kompatibel)
        const accessToken = `claude_token_${crypto.randomUUID().replace(/-/g, '')}`;

        // Token temporär speichern
        global.accessTokens = global.accessTokens || {};
        global.accessTokens[accessToken] = {
            client_id,
            scope: 'mcp:read mcp:execute tools:weather tools:memory',
            expires_at: Date.now() + (24 * 60 * 60 * 1000), // 24h
            token_type: 'bearer'
        };

        console.log('Access token generated for:', client_id);

        return [{
            json: {
                access_token: accessToken,
                token_type: 'Bearer',
                expires_in: 86400, // 24 Stunden
                scope: 'mcp:read mcp:execute tools:weather tools:memory'
            }
        }];
    }

    // Authorization Code Flow
    if (grant_type === 'authorization_code') {
        if (!code || !global.authCodes || !global.authCodes[code]) {
            return [{
                json: {
                    error: 'invalid_grant',
                    error_description: 'Invalid authorization code'
                }
            }];
        }

        const authData = global.authCodes[code];

        // Code bereits verwendet?
        if (authData.used || authData.expires_at < Date.now()) {
            delete global.authCodes[code];
            return [{
                json: {
                    error: 'invalid_grant',
                    error_description: 'Authorization code expired or already used'
                }
            }];
        }

        // Code als verwendet markieren
        authData.used = true;

        // Access Token generieren
        const accessToken = `claude_auth_${crypto.randomUUID().replace(/-/g, '')}`;

        global.accessTokens = global.accessTokens || {};
        global.accessTokens[accessToken] = {
            client_id: authData.client_id,
            scope: authData.scope,
            expires_at: Date.now() + (24 * 60 * 60 * 1000),
            token_type: 'bearer'
        };

        return [{
            json: {
                access_token: accessToken,
                token_type: 'Bearer',
                expires_in: 86400,
                scope: authData.scope
            }
        }];
    }

    return [{
        json: {
            error: 'unsupported_grant_type',
            error_description: 'Only client_credentials and authorization_code supported'
        }
    }];

} catch (error) {
    console.error('Token Generation Error:', error);
    return [{
        json: {
            error: 'server_error',
            error_description: 'Token generation failed: ' + error.message
        }
    }];
}

// Token-Validation für MCP-Server
try {
    const body = $('Token Validation Endpoint').first().json.body || {};
    const headers = $('Token Validation Endpoint').first().json.headers || {};

    let token = body.token || headers.authorization;

    if (token && token.startsWith('Bearer ')) {
        token = token.substring(7);
    }

    if (!token) {
        return [{
            json: {
                active: false,
                error: 'missing_token'
            }
        }];
    }

    // Token in temporärem Storage prüfen
    if (!global.accessTokens || !global.accessTokens[token]) {
        return [{
            json: {
                active: false,
                error: 'invalid_token'
            }
        }];
    }

    const tokenData = global.accessTokens[token];

    // Token-Expiration prüfen
    if (tokenData.expires_at < Date.now()) {
        delete global.accessTokens[token];
        return [{
            json: {
                active: false,
                error: 'token_expired'
            }
        }];
    }

    // Token ist valide
    return [{
        json: {
            active: true,
            client_id: tokenData.client_id,
            scope: tokenData.scope,
            token_type: tokenData.token_type,
            expires_in: Math.floor((tokenData.expires_at - Date.now()) / 1000)
        }
    }];

} catch (error) {
    console.error('Token Validation Error:', error);
    return [{
        json: {
            active: false,
            error: 'validation_failed'
        }
    }];
}
